import { Link } from 'react-router-dom';
import { formatPrice } from '../../utils/formatters';

const MenuItemCard = ({ item, onAddToCart }) => {
  return (
    <div className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow">
      <Link to={`/menu/${item._id}`}>
        <img
          src={item.image || 'https://via.placeholder.com/300x200?text=الشطبي'}
          alt={item.nameAr}
          className="w-full h-48 object-cover"
        />
      </Link>
      <div className="p-4">
        <Link to={`/menu/${item._id}`}>
          <h3 className="text-lg font-bold text-gray-800 mb-1">{item.nameAr}</h3>
        </Link>
        <p className="text-gray-600 text-sm mb-3 line-clamp-2">{item.descriptionAr}</p>
        <div className="flex justify-between items-center">
          <span className="text-xl font-bold text-primary-600">{formatPrice(item.price)}</span>
          <button
            onClick={() => onAddToCart({
              menuItem: item._id,
              name: item.nameAr,
              price: item.price,
              quantity: 1,
              options: []
            })}
            className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
          >
            أضف للسلة
          </button>
        </div>
      </div>
    </div>
  );
};

export default MenuItemCard;
